<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***APIuntukMasterDataKepegawaianPOLRI*JenisPenugasan,AlasanPenugasan,StatusJabatan*/require_once'../core/config.php';require_once'auth_helper.php';classMasterKepegawaianManager{private$db;public$auth;publicfunction__construct(){$this->db=newmysqli(DB_HOST,DB_USER,DB_PASS,DB_NAME);$this->auth=APIAuth::getInstance();}/***Getalljenispenugasan*/publicfunctiongetJenisPenugasan(){$query="SELECTid,kode,nama,nama_lengkap,deskripsi,kategori,level_minimal,durasi_maximal_bulan,kewenangan,persentase_maximal,is_activeFROMmaster_jenis_penugasanWHEREis_active=trueORDERBYid";$result=$this->db->query($query);$data=[];while($row=$result->fetch_assoc()){$data[]=$row;}return$data;}/***Getallalasanpenugasan*/publicfunctiongetAlasanPenugasan(){$query="SELECTid,kode,nama,kategori,deskripsi,durasi_rekomendasi_bulan,requires_sk,is_activeFROMmaster_alasan_penugasanWHEREis_active=trueORDERBYkategori,nama";$result=$this->db->query($query);$data=[];while($row=$result->fetch_assoc()){$data[]=$row;}return$data;}/***Getallstatusjabatan*/publicfunctiongetStatusJabatan(){$query="SELECTid,kode,nama,nama_lengkap,deskripsi,kategori,level_eselon,is_definitif,is_managerial,is_supervisor,is_activeFROMmaster_status_jabatanWHEREis_active=trueORDERBYlevel_eselon,nama";$result=$this->db->query($query);$data=[];while($row=$result->fetch_assoc()){$data[]=$row;}return$data;}/***Getjabatandenganmasterdata*/publicfunctiongetJabatanWithMaster(){$query="SELECTj.id,j.nama_jabatan,jp.namaasjenis_penugasan,jp.kodeaskode_penugasan,ap.namaasalasan_penugasan,ap.kodeaskode_alasan,sj.namaasstatus_jabatan,sj.kodeaskode_status,u.nama_unsur,COUNT(p.id)aspersonil_countFROMjabatanjLEFTJOINmaster_jenis_penugasanjpONj.id_jenis_penugasan=jp.idLEFTJOINmaster_alasan_penugasanapONj.id_alasan_penugasan=ap.idLEFTJOINmaster_status_jabatansjONj.id_status_jabatan=sj.idLEFTJOINunsuruONj.id_unsur=u.idLEFTJOINpersonilpONj.id=p.id_jabatanGROUPBYj.id,j.nama_jabatan,jp.nama,jp.kode,ap.nama,ap.kode,sj.nama,sj.kode,u.nama_unsurORDERBYu.urutan,j.nama_jabatan";$result=$this->db->query($query);$data=[];while($row=$result->fetch_assoc()){$data[]=$row;}return$data;}/***Updatestatuspenugasanjabatan*/publicfunctionupdateStatusPenugasan($jabatan_id,$jenis_penugasan_id,$alasan_penugasan_id,$tanggal_mulai,$tanggal_selesai,$keterangan){/Validatejabatan$jabatan=$this->getJabatanById($jabatan_id);if(!$jabatan){thrownewException("Jabatannotfound");}/Validatejenispenugasan$jenis_penugasan=$this->getJenisPenugasanById($jenis_penugasan_id);if(!$jenis_penugasan){thrownewException("Jenispenugasannotfound");}/Validatealasanpenugasan$alasan_penugasan=$this->getAlasanPenugasanById($alasan_penugasan_id);if(!$alasan_penugasan){thrownewException("Alasanpenugasannotfound");}/Validaterules$this->validatePenugasanRules($jabatan,$jenis_penugasan,$alasan_penugasan);/Updatejabatan$query="UPDATEjabatanSETid_jenis_penugasan=?,id_alasan_penugasan=?,tanggal_mulai_penugasan=?,tanggal_selesai_penugasan=?,keterangan_penugasan=?WHEREid=?";$stmt=$this->db->prepare($query);$stmt->bind_param("iisssi",$jenis_penugasan_id,$alasan_penugasan_id,$tanggal_mulai,$tanggal_selesai,$keterangan,$jabatan_id);$stmt->execute();/Updatepersonilassignment$this->updatePersonilPenugasan($jabatan_id,$jenis_penugasan_id,$alasan_penugasan_id,$tanggal_mulai,$tanggal_selesai,$keterangan);returntrue;}/***Getpenugasanstatistics*/publicfunctiongetPenugasanStats(){$query="SELECTjp.namaasjenis_penugasan,jp.kodeaskode_penugasan,COUNT(DISTINCTj.id)asjabatan_count,COUNT(DISTINCTp.id)aspersonil_count,ROUND(COUNT(DISTINCTj.id)*100.0/(SELECTCOUNT(*)FROMjabatan),2)aspercentageFROMjabatanjLEFTJOINmaster_jenis_penugasanjpONj.id_jenis_penugasan=jp.idLEFTJOINpersonilpONj.id=p.id_jabatanGROUPBYjp.id,jp.nama,jp.kodeORDERBYjabatan_countDESC";$result=$this->db->query($query);$stats=[];while($row=$result->fetch_assoc()){$stats[]=$row;}return$stats;}/***Getexpiredpenugasan*/publicfunctiongetExpiredPenugasan(){$query="SELECTj.id,j.nama_jabatan,jp.namaasjenis_penugasan,ap.namaasalasan_penugasan,j.tanggal_selesai_penugasan,p.namaaspersonil_nama,DATEDIFF(CURDATE(),j.tanggal_selesai_penugasan)asdays_expiredFROMjabatanjLEFTJOINmaster_jenis_penugasanjpONj.id_jenis_penugasan=jp.idLEFTJOINmaster_alasan_penugasanapONj.id_alasan_penugasan=ap.idLEFTJOINpersonilpONj.id=p.id_jabatanWHEREj.id_jenis_penugasanISNOTnullANDj.tanggal_selesai_penugasan<CURDATE()ORDERBYdays_expiredDESC";$result=$this->db->query($query);$expired=[];while($row=$result->fetch_assoc()){$expired[]=$row;}return$expired;}/***Validatepenugasanrules*/privatefunctionvalidatePenugasanRules($jabatan,$jenis_penugasan,$alasan_penugasan){/Checklevelminimal$level_ok=$this->checkLevelRequirement($jabatan,$jenis_penugasan);if(!$level_ok){thrownewException("Jenispenugasantidaksesuaiuntukleveljabatanini");}/CheckpercentagelimitforPSif($jenis_penugasan'\1\'=>=='PS'){$ps_count=$this->getPSCount();$total_jabatan=$this->getTotalJabatan();$ps_percentage=($ps_count/$total_jabatan)*100;if($ps_percentage>$jenis_penugasan['persentase_maximal']){thrownewException("PSmelebihibatasmaksimal".$jenis_penugasan['persentase_maximal']."%");}}/Checkdurationlimitif($jenis_penugasan['durasi_maximal_bulan']){$duration=$this->calculateDuration($jenis_penugasan['durasi_maximal_bulan']);if($duration>$jenis_penugasan['durasi_maximal_bulan']){thrownewException("Durasipenugasanmelebihibatasmaksimal".$jenis_penugasan['durasi_maximal_bulan']."bulan");}}/CheckSKrequirementif($alasan_penugasan['requires_sk']){/TODO:CheckifSKexists}}/***Helpermethods*/privatefunctiongetJabatanById($id){$query="SELECTj.*,sj.namaasstatus_jabatan,sj.level_eselonFROMjabatanjLEFTJOINmaster_status_jabatansjONj.id_status_jabatan=sj.idWHEREj.id=?";$stmt=$this->db->prepare($query);$stmt->bind_param("i",$id);$stmt->execute();return$stmt->get_result()->fetch_assoc();}privatefunctiongetJenisPenugasanById($id){$query="SELECT*FROMmaster_jenis_penugasanWHEREid=?";$stmt=$this->db->prepare($query);$stmt->bind_param("i",$id);$stmt->execute();return$stmt->get_result()->fetch_assoc();}privatefunctiongetAlasanPenugasanById($id){$query="SELECT*FROMmaster_alasan_penugasanWHEREid=?";$stmt=$this->db->prepare($query);$stmt->bind_param("i",$id);$stmt->execute();return$stmt->get_result()->fetch_assoc();}privatefunctiongetPSCount(){$query="SELECTCOUNT(*)ascountFROMjabatanjJOINmaster_jenis_penugasanjpONj.id_jenis_penugasan=jp.idWHEREjp.kode='PS'";$result=$this->db->query($query);return$result->fetch_assoc()['count'];}privatefunctiongetTotalJabatan(){$query="SELECTCOUNT(*)ascountFROMjabatan";$result=$this->db->query($query);return$result->fetch_assoc()['count'];}privatefunctioncheckLevelRequirement($jabatan,$jenis_penugasan){$level_map='\1\'=>\2,'eselon_3'=>['KABAG','KASAT','KAPOLSEK'],'eselon_4'=>['KASUBBAG','KASUBSAT'],'eselon_5'=>['KANIT','KAUR'],'semua_level'=>['all']];if($jenis_penugasan'\1\'=>=='semua_level'){returntrue;}$allowed_levels=$level_map[$jenis_penugasan['level_minimal']]??[];$jabatan_level=$jabatan['level_eselon']??'non_eselon';returnin_array($jabatan_level,$allowed_levels);}privatefunctioncalculateDuration($max_months){/TODO:Implementdurationcalculationreturn0;}privatefunctionupdatePersonilPenugasan($jabatan_id,$jenis_penugasan_id,$alasan_penugasan_id,$tanggal_mulai,$tanggal_selesai,$keterangan){$query="UPDATEpersonilSETid_jenis_penugasan=?,id_alasan_penugasan=?,tanggal_mulai_penugasan=?,tanggal_selesai_penugasan=?,keterangan_penugasan=?WHEREid_jabatan=?";$stmt=$this->db->prepare($query);$stmt->bind_param("iisssi",$jenis_penugasan_id,$alasan_penugasan_id,$tanggal_mulai,$tanggal_selesai,$keterangan,$jabatan_id);$stmt->execute();}}/APIHandlertry{$master=newMasterKepegawaianManager();$action=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2{case'get_jenis_penugasan':/$master->auth->requireAuth();/Commentedfortesting$data=$master->getJenisPenugasan();echojson_encode('\1\'=>\2);break;case'get_alasan_penugasan':/$master->auth->requireAuth();/Commentedfortesting$data=$master->getAlasanPenugasan();echojson_encode('\1\'=>\2);break;case'get_status_jabatan':/$master->auth->requireAuth();/Commentedfortesting$data=$master->getStatusJabatan();echojson_encode('\1\'=>\2);break;case'get_jabatan_with_master':/$master->auth->requireAuth();/Commentedfortesting$data=$master->getJabatanWithMaster();echojson_encode('\1\'=>\2);break;case'update_status_penugasan':$master->auth->requireAuth();$jabatan_id=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2,'jenis_penugasan_id',FILTER_DEFAULT)??0;$alasan_penugasan_id=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2,'tanggal_mulai',FILTER_DEFAULT)??null;$tanggal_selesai=filter_input(INPUT_POST,\'\1\',FILTER_DEFAULT)??\2,'keterangan',FILTER_DEFAULT)??'';$master->updateStatusPenugasan($jabatan_id,$jenis_penugasan_id,$alasan_penugasan_id,$tanggal_mulai,$tanggal_selesai,$keterangan);echojson_encode('\1\'=>\2);break;case'get_penugasan_stats':$master->auth->requireAuth();$stats=$master->getPenugasanStats();echojson_encode('\1\'=>\2);break;case'get_expired_penugasan':$master->auth->requireAuth();$expired=$master->getExpiredPenugasan();echojson_encode('\1\'=>\2);break;default:header('HTTP/1.0400BadRequest');echojson_encode('\1\'=>\2);}}catch(Exception$e){header('HTTP/1.0500InternalServerError');echojson_encode('\1\'=>\2);}?>
